static uint32_t rnd(void){rngState^=rngState<<13;rngState^=rngState>>17;rngState^=rngState<<5;return rngState;}
static int irand(int n){return n?(int)(rnd()%(uint32_t)n):0;} static float frand(void){return (rnd()&0xffffff)/16777215.0f;}
static float clampf(float v,float a,float b){return v<a?a:v>b?b:v;} static int pressed(int k){return keys[k]&&!prevKeys[k];}
static float dist2(float x,float y,float a,float b){float dx=x-a,dy=y-b;return dx*dx+dy*dy;}
static void fill(HDC dc,int x,int y,int w,int h,COLORREF c){HBRUSH b=CreateSolidBrush(c);RECT r={x,y,x+w,y+h};FillRect(dc,&r,b);DeleteObject(b);}
static void outline(HDC dc,int x,int y,int w,int h,COLORREF c,int t){HPEN p=CreatePen(PS_SOLID,t,c);HPEN op=(HPEN)SelectObject(dc,p);HBRUSH ob=(HBRUSH)SelectObject(dc,GetStockObject(NULL_BRUSH));Rectangle(dc,x,y,x+w,y+h);SelectObject(dc,ob);SelectObject(dc,op);DeleteObject(p);}
static void line(HDC dc,int x1,int y1,int x2,int y2,COLORREF c,int t){HPEN p=CreatePen(PS_SOLID,t,c);HPEN op=(HPEN)SelectObject(dc,p);MoveToEx(dc,x1,y1,0);LineTo(dc,x2,y2);SelectObject(dc,op);DeleteObject(p);}
static void txt(HDC dc,int x,int y,int sz,COLORREF c,const char*s){HFONT f=CreateFontA(sz,0,0,0,FW_BOLD,0,0,0,ANSI_CHARSET,OUT_DEFAULT_PRECIS,CLIP_DEFAULT_PRECIS,NONANTIALIASED_QUALITY,FIXED_PITCH|FF_MODERN,"Consolas");HFONT of=(HFONT)SelectObject(dc,f);SetBkMode(dc,TRANSPARENT);SetTextColor(dc,c);TextOutA(dc,x,y,s,(int)strlen(s));SelectObject(dc,of);DeleteObject(f);}
static void center(HDC dc,int y,int sz,COLORREF c,const char*s){SIZE q;HFONT f=CreateFontA(sz,0,0,0,FW_BOLD,0,0,0,ANSI_CHARSET,OUT_DEFAULT_PRECIS,CLIP_DEFAULT_PRECIS,NONANTIALIASED_QUALITY,FIXED_PITCH|FF_MODERN,"Consolas");HFONT of=(HFONT)SelectObject(dc,f);GetTextExtentPoint32A(dc,s,(int)strlen(s),&q);SelectObject(dc,of);DeleteObject(f);txt(dc,(W-q.cx)/2,y,sz,c,s);}
static void setStatus(const char*s){lstrcpynA(statusLine,s,sizeof(statusLine));statusTimer=2.2f;}
static void fx(int kind){if(!soundOn)return;MessageBeep(kind?MB_ICONEXCLAMATION:MB_OK);}

static void saveData(void){FILE*f=fopen("bad_sector.sav","wb");if(f){fwrite(highScores,sizeof(highScores),1,f);fwrite(&achievements,sizeof(achievements),1,f);fwrite(&difficulty,sizeof(difficulty),1,f);fwrite(&musicOn,sizeof(musicOn),1,f);fwrite(&soundOn,sizeof(soundOn),1,f);fclose(f);}}
static void loadData(void){FILE*f=fopen("bad_sector.sav","rb");if(f){fread(highScores,sizeof(highScores),1,f);fread(&achievements,sizeof(achievements),1,f);fread(&difficulty,sizeof(difficulty),1,f);fread(&musicOn,sizeof(musicOn),1,f);fread(&soundOn,sizeof(soundOn),1,f);fclose(f);}}
static void submitScore(int s){int i,j;for(i=0;i<5;i++)if(s>highScores[i]){for(j=4;j>i;j--)highScores[j]=highScores[j-1];highScores[i]=s;break;}saveData();}

static void stopMusic(void){if(waveOut){waveOutReset(waveOut);waveOutUnprepareHeader(waveOut,&musicHdr,sizeof(musicHdr));waveOutClose(waveOut);waveOut=0;}if(musicData){free(musicData);musicData=0;}}
static void startMusic(int tense){int rate=22050,seconds=12,n=rate*seconds,i;WAVEFORMATEX fmt={WAVE_FORMAT_PCM,1,rate,rate,1,8,0};static const int notesA[]={262,330,392,523,392,330,294,392,247,330,370,494,370,330,262,330};static const int notesB[]={110,147,165,220,123,165,185,247,98,131,147,196,110,147,175,220};stopMusic();if(!musicOn)return;musicData=(uint8_t*)malloc(n);if(!musicData)return;for(i=0;i<n;i++){double t=(double)i/rate;int step=(int)(t*4)%16;double f=(tense?notesB[step]:notesA[step]);double sq=fmod(t*f,1.0)<.5?1:-1;double bass=fmod(t*(f*.5),1.0)<.5?1:-1;double beat=fmod(t*4,1.0)<.06?(1.0-fmod(t*4,1.0)/.06):0;int v=(int)(128+18*sq+10*bass+10*beat*((i*37)&1?1:-1));musicData[i]=(uint8_t)(v<0?0:v>255?255:v);}ZeroMemory(&musicHdr,sizeof(musicHdr));musicHdr.lpData=(LPSTR)musicData;musicHdr.dwBufferLength=n;if(waveOutOpen(&waveOut,WAVE_MAPPER,&fmt,0,0,CALLBACK_NULL)==MMSYSERR_NOERROR){waveOutPrepareHeader(waveOut,&musicHdr,sizeof(musicHdr));musicHdr.dwFlags|=WHDR_BEGINLOOP;musicHdr.dwLoops=0xffffffff;waveOutWrite(waveOut,&musicHdr,sizeof(musicHdr));}}

static void particle(float x,float y,int kind,int count){int i,j;for(j=0;j<count;j++)for(i=0;i<MAX_PARTICLES;i++)if(!particles[i].active){float a=frand()*6.283f,s=.7f+frand()*3;particles[i]=(Particle){x,y,(float)cos(a)*s,(float)sin(a)*s,.35f+frand()*.7f,1,kind};break;}}
static int wallAt(int x,int y){int i;for(i=0;i<MAX_WALLS;i++)if(walls[i].active&&walls[i].x==x&&walls[i].y==y)return 1;return 0;}
static void addWall(int x,int y){int i;for(i=0;i<MAX_WALLS;i++)if(!walls[i].active){walls[i]=(Wall){x,y,8,1};return;}}
static void clearEntities(void){ZeroMemory(enemies,sizeof(enemies));ZeroMemory(particles,sizeof(particles));ZeroMemory(walls,sizeof(walls));}
static int damagedSectorCount(void){int x,y,n=0;for(y=0;y<GH;y++)for(x=0;x<GW;x++)if(grid[y][x].type!=S_CLEAN)n++;return n;}
static int sectorsRemaining(void){int byRepairs=repairedGoal-run.repairs,visible=damagedSectorCount();if(byRepairs<0)byRepairs=0;return visible<byRepairs?visible:byRepairs;}
static const char* sectorName(int t){switch(t){case S_CORRUPT:return "CORRUPT SECTOR";case S_FRAGMENTED:return "FRAGMENTED SECTOR";case S_INFECTED:return "INFECTED SECTOR";case S_ENCRYPTED:return "ENCRYPTED SECTOR";case S_UNSTABLE:return "UNSTABLE SECTOR";case S_PROTECTED:return "PROTECTED DATA";default:return "CLEAN SECTOR";}}
static const char* sectorHelp(int t){switch(t){case S_CORRUPT:return "Standard damage. Hold SPACE for one second.";case S_FRAGMENTED:return "Orange and cracked. Takes about twice as long to rebuild.";case S_INFECTED:return "Purple. Finishing the repair releases a virus.";case S_ENCRYPTED:return "Green pulse. Repair only while the sector is bright green.";case S_UNSTABLE:return "Yellow. It can spread corruption to a neighboring sector.";case S_PROTECTED:return "Blue P. Slow to recover, but worth bonus points.";default:return "";}}
static int introducedSectorForStage(int stage){if(stage<=0)return S_CORRUPT;if(stage==1)return S_FRAGMENTED;if(stage==2)return S_INFECTED;if(stage==3)return S_UNSTABLE;if(stage==4)return S_ENCRYPTED;if(stage==5)return S_PROTECTED;return -1;}
static SectorType randomSector(void){int r=irand(100),stage=challengeMode?9:stageIndex;if(stage<=0)return S_CORRUPT;if(stage==1)return r<65?S_CORRUPT:S_FRAGMENTED;if(stage==2)return r<55?S_CORRUPT:r<80?S_FRAGMENTED:S_INFECTED;if(stage==3)return r<46?S_CORRUPT:r<68?S_FRAGMENTED:r<84?S_INFECTED:S_UNSTABLE;if(stage==4)return r<40?S_CORRUPT:r<58?S_FRAGMENTED:r<72?S_INFECTED:r<86?S_UNSTABLE:S_ENCRYPTED;return r<34?S_CORRUPT:r<50?S_FRAGMENTED:r<63?S_INFECTED:r<75?S_UNSTABLE:r<88?S_ENCRYPTED:S_PROTECTED;}
static float repairNeed(int type){if(type==S_FRAGMENTED)return 2.2f;if(type==S_INFECTED)return 1.5f;if(type==S_PROTECTED)return 2.6f;return 1.0f;}
static void corruptRandom(int count){while(count--){int x=irand(GW),y=irand(GH);if(grid[y][x].type==S_CLEAN){grid[y][x].type=randomSector();grid[y][x].timer=frand()*2;}}}
static void stageSetup(void){int x,y,i;const Stage*s=&stages[stageIndex];for(y=0;y<GH;y++)for(x=0;x<GW;x++){grid[y][x]=(Sector){S_CLEAN,1,0,0,0,0};}clearEntities();corruptRandom(s->corrupt);if(stageIndex==0&&!challengeMode){for(y=0;y<GH;y++)for(x=0;x<GW;x++)if(grid[y][x].type!=S_CLEAN)grid[y][x].type=S_CORRUPT;}px=GW*.5f;py=GH*.5f;invuln=2.0f;spawnTimer=!challengeMode&&stageIndex==0?18.0f:!challengeMode&&stageIndex==1?14.0f:!challengeMode&&stageIndex==2?10.0f:!challengeMode&&stageIndex==3?8.0f:5.0f;spreadTimer=!challengeMode&&stageIndex<3?999.0f:!challengeMode&&stageIndex==3?6.0f:3.5f;stageClock=(float)s->timeLimit;stageIntro=5.0f;screenShake=0;magnetPulse=0;overclock=0;sectorLock=0;repairedGoal=s->target;run.repairs=0;run.combo=0;selectedTool=TOOL_PULSE;for(i=0;i<TOOL_COUNT;i++)toolCharges[i]=2;toolCharges[TOOL_PULSE]=4;toolCharges[TOOL_REBOOT]=1;if(s->boss){for(i=0;i<3;i++){enemies[i]=(Enemy){i?GW-3:2,2+i*5,0,0,0,0,1,E_MAGNET,8};}}startMusic(stageIndex>=12);}
static void newGame(int challenge){int i;SYSTEMTIME st;challengeMode=challenge;GetLocalTime(&st);if(challenge){rngState=(uint32_t)(st.wYear*10000+st.wMonth*100+st.wDay)^0x1440BEEF;stageIndex=4+(int)(rngState%12);}else{rngState=0x1440BEEFu;stageIndex=0;}run=(RunStats){0,1,3,100,0,0,0,0,0};for(i=0;i<2;i++){pScores[i]=0;pLives[i]=3;}currentPlayer=0;stageSetup();introTime=0;mode=M_INTRO;}
static int chooseEnemy(int mask){int choices[6],n=0,i;for(i=0;i<6;i++)if(mask&(1<<i))choices[n++]=i;return n?choices[irand(n)]:E_VIRUS;}
static void spawnEnemyType(int type,float x,float y){int i;for(i=0;i<MAX_ENEMIES;i++)if(!enemies[i].active){float sp=(!challengeMode&&stageIndex==0?.42f:!challengeMode&&stageIndex==1?.48f:!challengeMode&&stageIndex==2?.56f:!challengeMode&&stageIndex==3?.66f:.78f)+difficulty*.10f+stageIndex*.022f;enemies[i]=(Enemy){x,y,(frand()-.5f)*sp,(frand()-.5f)*sp,0,frand()*6,1,type,type==E_CLUSTER?2:type==E_MAGNET?8:1};return;}}
static void spawnEnemy(void){int edge=irand(4),type=chooseEnemy(stages[stageIndex].enemyMask);float x,y;if(edge==0){x=0;y=irand(GH);}else if(edge==1){x=GW-1;y=irand(GH);}else if(edge==2){x=irand(GW);y=0;}else{x=irand(GW);y=GH-1;}spawnEnemyType(type,x,y);}
static void damage(void){if(invuln>0)return;run.lives--;pLives[currentPlayer]=run.lives;run.combo=0;invuln=1.8f;screenShake=12;particle(px,py,2,24);fx(1);setStatus("READ ERROR - LIFE LOST");if(run.lives<=0){if(twoPlayer&&pLives[1-currentPlayer]>0){pScores[currentPlayer]=run.score;currentPlayer=1-currentPlayer;run.score=pScores[currentPlayer];run.lives=pLives[currentPlayer];stageSetup();mode=M_STORY;setStatus("PLAYER SWITCH");}else{submitScore(run.score+pScores[1-currentPlayer]);mode=M_GAMEOVER;stopMusic();}}}
static void killEnemy(int i,int points){particle(enemies[i].x,enemies[i].y,1,12);run.score+=points;enemies[i].active=0;}
static void useTool(void){int i,x=(int)(px+.5f),y=(int)(py+.5f);if(toolCharges[selectedTool]<=0){setStatus("UTILITY EMPTY");return;}toolCharges[selectedTool]--;switch(selectedTool){case TOOL_PULSE:for(i=0;i<MAX_ENEMIES;i++)if(enemies[i].active&&dist2(px,py,enemies[i].x,enemies[i].y)<16)killEnemy(i,75);particle(px,py,0,40);setStatus("ANTIVIRUS PULSE");break;case TOOL_LOCK:sectorLock=8;setStatus("SECTOR LOCK: SPREAD PAUSED");break;case TOOL_BEAM:for(i=0;i<GW;i++){grid[y][i].type=S_CLEAN;grid[y][i].repair=0;}run.score+=250;setStatus("DEFRAG BEAM: TRACK CLEANED");break;case TOOL_BACKUP:for(i=0;i<12;i++){int a=irand(GW),b=irand(GH);grid[b][a].type=S_CLEAN;grid[b][a].repair=0;}setStatus("BACKUP RESTORE");break;case TOOL_OVERCLOCK:overclock=10;setStatus("OVERCLOCK ENABLED");break;case TOOL_FIREWALL:addWall(x,y);if(x>0)addWall(x-1,y);if(x<GW-1)addWall(x+1,y);setStatus("FIREWALL DEPLOYED");break;case TOOL_REBOOT:for(i=0;i<MAX_ENEMIES;i++)if(enemies[i].active)killEnemy(i,20);corruptRandom(5);invuln=3;setStatus("EMERGENCY REBOOT");break;default:break;}fx(0);}
static void repairCell(float dt){int x=(int)(px+.5f),y=(int)(py+.5f);Sector*s=&grid[y][x];float need=repairNeed(s->type);if(s->type==S_CLEAN)return;if(s->type==S_ENCRYPTED&&fmod(s->timer,2.0f)>0.75f){setStatus("ENCRYPTED: WAIT FOR GREEN PULSE");return;}s->repair+=dt*(overclock>0?2.2f:1.0f);if(s->repair>=need){SectorType old=(SectorType)s->type;s->type=S_CLEAN;s->repair=0;run.repairs++;run.combo++;if(run.combo>run.maxCombo)run.maxCombo=run.combo;run.score+=100+run.combo*12+(old==S_PROTECTED?300:0);run.energy=run.energy<100?run.energy+3:100;if(old==S_INFECTED)spawnEnemyType(E_VIRUS,x,y);if(old==S_PROTECTED)run.protectedSaved++;particle(x,y,0,14);fx(0);if(run.combo==10){achievements|=1;setStatus("ACHIEVEMENT: TEN-SECTOR COMBO");}else setStatus("SECTOR RECOVERED");}}
static void completeStage(void){stageBonus=(int)(stageClock*25)+1000+run.combo*20;run.score+=stageBonus;if(run.protectedSaved>=10)achievements|=2;if(challengeMode){submitScore(run.score);mode=M_VICTORY;stopMusic();saveData();return;}if(stageIndex==19){achievements|=4;submitScore(run.score+pScores[1-currentPlayer]);mode=M_VICTORY;stopMusic();saveData();return;}completedStage=stageIndex;completeTime=0;mode=M_COMPLETE;fx(0);}

static void updateEnemies(float dt){int i;for(i=0;i<MAX_ENEMIES;i++)if(enemies[i].active){Enemy*e=&enemies[i];float dx=px-e->x,dy=py-e->y,d=(float)sqrt(dx*dx+dy*dy)+.001f;e->timer+=dt;switch(e->type){case E_VIRUS:e->vx+=dx/d*dt*1.4f;e->vy+=dy/d*dt*1.4f;break;case E_WORM:e->vx+=dx/d*dt*.35f;e->vy+=dy/d*dt*.35f;if(e->timer>.35f){int x=(int)e->x,y=(int)e->y;if(x>=0&&y>=0&&x<GW&&y<GH&&grid[y][x].type==S_CLEAN)grid[y][x].type=S_CORRUPT;e->timer=0;}break;case E_TROJAN:if(d<3.2f){e->vx+=dx/d*dt*2.8f;e->vy+=dy/d*dt*2.8f;}else{e->vx*=.97f;e->vy*=.97f;}break;case E_CLUSTER:e->vx+=dx/d*dt*.8f;e->vy+=dy/d*dt*.8f;break;case E_SWEEPER:if(e->aux<3.14f){e->vx=2.8f;e->vy=0;}else{e->vx=0;e->vy=2.8f;}break;case E_MAGNET:{float pull=(stages[stageIndex].boss?2.4f:1.4f)/(d+.5f);px+=(-dx/d)*pull*dt;py+=(-dy/d)*pull*dt;e->vx+=(float)sin(e->timer)*dt;e->vy+=(float)cos(e->timer*.8f)*dt;}break;}e->vx=clampf(e->vx,-3.7f,3.7f);e->vy=clampf(e->vy,-3.7f,3.7f);e->x+=e->vx*dt;e->y+=e->vy*dt;if(e->x<0)e->x=GW-1;if(e->x>GW-1)e->x=0;if(e->y<0)e->y=GH-1;if(e->y>GH-1)e->y=0;if(wallAt((int)(e->x+.5f),(int)(e->y+.5f))){e->vx=-e->vx;e->vy=-e->vy;e->x+=e->vx*.2f;e->y+=e->vy*.2f;}if(dist2(px,py,e->x,e->y)<.42f){if(e->type==E_CLUSTER&&e->hp>1){e->hp=1;spawnEnemyType(E_VIRUS,e->x+.4f,e->y);spawnEnemyType(E_VIRUS,e->x-.4f,e->y);killEnemy(i,100);}else if(e->type!=E_MAGNET)killEnemy(i,25);damage();}}}
static int activeEnemyCount(void){int i,n=0;for(i=0;i<MAX_ENEMIES;i++)if(enemies[i].active)n++;return n;}
static void updateWorld(float dt){int x,y,i;const Stage*s=&stages[stageIndex];float dx=0,dy=0,speed=6.5f+(overclock>0?3.2f:0);if(pressed(VK_ESCAPE)){mode=M_PAUSE;return;}if(pressed('Q')){selectedTool=(selectedTool+TOOL_COUNT-1)%TOOL_COUNT;}if(pressed('E')){selectedTool=(selectedTool+1)%TOOL_COUNT;}for(i=0;i<TOOL_COUNT;i++)if(pressed('1'+i))selectedTool=i;if(pressed(VK_RETURN)||pressed('F'))useTool();if(keys['A']||keys[VK_LEFT])dx--;if(keys['D']||keys[VK_RIGHT])dx++;if(keys['W']||keys[VK_UP])dy--;if(keys['S']||keys[VK_DOWN])dy++;if(dx&&dy){dx*=.7071f;dy*=.7071f;}px=clampf(px+dx*speed*dt,0,GW-1);py=clampf(py+dy*speed*dt,0,GH-1);if(keys[VK_SPACE])repairCell(dt);stageClock-=dt*(difficulty==0?.85f:difficulty==2?1.15f:1);if(stageClock<=0){damage();stageClock=12;}if(invuln>0)invuln-=dt;if(overclock>0)overclock-=dt;if(sectorLock>0)sectorLock-=dt;if(statusTimer>0)statusTimer-=dt;spawnTimer-=dt;if(spawnTimer<=0){int cap=!challengeMode&&stageIndex==0?1:!challengeMode&&stageIndex==1?2:!challengeMode&&stageIndex==2?3:!challengeMode&&stageIndex==3?4:5+stageIndex/2;if(activeEnemyCount()<cap)spawnEnemy();spawnTimer=!challengeMode&&stageIndex<2?12.0f:!challengeMode&&stageIndex==2?9.0f:!challengeMode&&stageIndex==3?7.0f:clampf(6.0f-stageIndex*.10f-difficulty*.16f,1.4f,6.0f);}spreadTimer-=dt;if(spreadTimer<=0&&sectorLock<=0&&(!challengeMode?stageIndex>=3:1)){corruptRandom(stageIndex>11?2:1);spreadTimer=!challengeMode&&stageIndex==3?7.0f:clampf(4.8f-stageIndex*.07f,1.1f,4.8f);}magnetPulse+=dt;if(s->magnet){float polarity=(float)sin(magnetPulse*1.7f),cx=GW*.5f,cy=GH*.5f,mdx=cx-px,mdy=cy-py,dd=(float)sqrt(mdx*mdx+mdy*mdy)+.1f;px+=mdx/dd*polarity*dt*(.55f+stageIndex*.025f);py+=mdy/dd*polarity*dt*(.55f+stageIndex*.025f);}for(y=0;y<GH;y++)for(x=0;x<GW;x++){Sector*c=&grid[y][x];c->timer+=dt;if(c->type==S_UNSTABLE&&sectorLock<=0&&c->timer>1.8f){int nx=x+(irand(3)-1),ny=y+(irand(3)-1);if(nx>=0&&ny>=0&&nx<GW&&ny<GH&&grid[ny][nx].type==S_CLEAN)grid[ny][nx].type=S_CORRUPT;c->timer=0;}}for(i=0;i<MAX_WALLS;i++)if(walls[i].active){walls[i].life-=dt;if(walls[i].life<=0)walls[i].active=0;}for(i=0;i<MAX_PARTICLES;i++)if(particles[i].active){particles[i].x+=particles[i].vx*dt;particles[i].y+=particles[i].vy*dt;particles[i].life-=dt;if(particles[i].life<=0)particles[i].active=0;}updateEnemies(dt);if(run.repairs>=repairedGoal||damagedSectorCount()==0)completeStage();}
static void update(float dt){if(mode==M_TITLE){if(pressed(VK_RETURN))newGame(0);if(pressed('C'))newGame(1);if(pressed('2'))twoPlayer=!twoPlayer;if(pressed('H'))mode=M_SCORES;if(pressed('O'))mode=M_SETTINGS;}else if(mode==M_INTRO){introTime+=dt;if(pressed(VK_SPACE)||pressed(VK_ESCAPE)||pressed(VK_RETURN)||introTime>=9.2f)mode=M_STORY;}else if(mode==M_STORY){if(pressed(VK_RETURN)||pressed(VK_SPACE))mode=M_PLAY;}else if(mode==M_PLAY)updateWorld(dt);else if(mode==M_COMPLETE){completeTime+=dt;if(pressed(VK_RETURN)||pressed(VK_SPACE)){stageIndex=completedStage+1;run.level=stageIndex+1;stageSetup();mode=M_STORY;}}else if(mode==M_PAUSE){if(pressed(VK_ESCAPE)||pressed(VK_RETURN))mode=M_PLAY;if(pressed('R')){stageSetup();mode=M_STORY;}if(pressed('Q')){mode=M_TITLE;stopMusic();}}else if(mode==M_GAMEOVER||mode==M_VICTORY){if(pressed(VK_RETURN)){mode=M_TITLE;startMusic(0);}}else if(mode==M_SCORES){if(pressed(VK_ESCAPE)||pressed(VK_RETURN))mode=M_TITLE;}else if(mode==M_SETTINGS){if(pressed(VK_UP)||pressed('W'))difficulty=(difficulty+2)%3;if(pressed(VK_DOWN)||pressed('S'))difficulty=(difficulty+1)%3;if(pressed('M')){musicOn=!musicOn;if(musicOn)startMusic(0);else stopMusic();}if(pressed('X'))soundOn=!soundOn;if(pressed(VK_ESCAPE)||pressed(VK_RETURN)){saveData();mode=M_TITLE;}}}

static COLORREF sectorColor(int t,float timer){switch(t){case S_CORRUPT:return RGB(208,55,74);case S_FRAGMENTED:return RGB(230,132,48);case S_INFECTED:return RGB(165,55,210);case S_ENCRYPTED:return fmod(timer,2)<.75?RGB(55,210,125):RGB(40,105,85);case S_UNSTABLE:return RGB(245,210,55);case S_PROTECTED:return RGB(50,145,235);default:return RGB(17,45,54);}}
static void drawMagnet(HDC dc,int x,int y,int scale,COLORREF c){fill(dc,x,y,scale,scale*2,c);fill(dc,x+scale*2,y,scale,scale*2,c);fill(dc,x,y+scale*2,scale*3,scale,c);fill(dc,x,y,scale,scale/2,RGB(230,235,240));fill(dc,x+scale*2,y,scale,scale/2,RGB(230,235,240));}
static void drawBot(HDC dc,int x,int y,int repairing){fill(dc,x+8,y+8,18,17,RGB(70,235,190));outline(dc,x+7,y+7,20,19,RGB(235,255,248),2);fill(dc,x+11,y+12,4,4,RGB(8,35,32));fill(dc,x+20,y+12,4,4,RGB(8,35,32));fill(dc,x+5,y+25,9,5,RGB(110,135,145));fill(dc,x+21,y+25,9,5,RGB(110,135,145));line(dc,x+17,y+7,x+17,y+2,RGB(255,220,75),2);fill(dc,x+15,y,5,4,RGB(255,220,75));if(repairing){line(dc,x+17,y+26,x+17,y+34,RGB(100,255,215),3);fill(dc,x+14,y+31,7,3,RGB(255,245,160));}}
